#include <iostream>

class Solution {
public:
    int gcd(int a, int b) {
        while (b) {
            int temp = b;
            b = a % b;
            a = temp;
        }
        return a;
    }
};

testCases = int(input())
for i in range(testCases):
    a, b = map(int, input().split())
    sol = Solution()
    print(sol.gcd(a, b))
